/**
 * Tests for GIF & Social Media Export Engine
 * Feature #77: GIF & Social Media Export
 */

import {
  buildGifArgs,
  buildSocialExportArgs,
  estimateGifSize,
  estimateSocialSize,
  validateGifOptions,
  validateSocialOptions,
  getPreset,
  listPresets,
  getPresetsForAspectRatio,
  estimateExport,
  SOCIAL_PRESETS,
  GIF_MAX_DURATION,
  GIF_MAX_WIDTH,
  GIF_MIN_FPS,
  GIF_MAX_FPS,
} from '@lib/export/gif-social-export';
import type {
  GifExportOptions,
  SocialExportOptions,
  SocialMediaPreset,
  SocialPlatform,
} from '@lib/export/gif-social-export';

// ─── Helper: default valid GIF options ─────────────────────────────────

function makeGifOptions(overrides?: Partial<GifExportOptions>): GifExportOptions {
  return {
    inputPath: '/tmp/input.mp4',
    outputPath: '/tmp/output.gif',
    width: 480,
    fps: 15,
    quality: 'medium',
    loop: 0,
    dither: 'bayer',
    ...overrides,
  };
}

function makeSocialOptions(overrides?: Partial<SocialExportOptions>): SocialExportOptions {
  return {
    inputPath: '/tmp/input.mp4',
    outputPath: '/tmp/output.mp4',
    preset: SOCIAL_PRESETS.instagram_reel,
    ...overrides,
  };
}

// ─── buildGifArgs ──────────────────────────────────────────────────────

describe('buildGifArgs', () => {
  it('should return paletteArgs, gifArgs, and palettePath', () => {
    const result = buildGifArgs(makeGifOptions());
    expect(result).toHaveProperty('paletteArgs');
    expect(result).toHaveProperty('gifArgs');
    expect(result).toHaveProperty('palettePath');
    expect(Array.isArray(result.paletteArgs)).toBe(true);
    expect(Array.isArray(result.gifArgs)).toBe(true);
    expect(typeof result.palettePath).toBe('string');
  });

  it('should include input path in paletteArgs', () => {
    const result = buildGifArgs(makeGifOptions());
    expect(result.paletteArgs).toContain('/tmp/input.mp4');
  });

  it('should include width and fps in palette filter', () => {
    const result = buildGifArgs(makeGifOptions({ width: 320, fps: 20 }));
    const vfArg = result.paletteArgs.find((a) => a.includes('fps='));
    expect(vfArg).toContain('fps=20');
    expect(vfArg).toContain('scale=320');
  });

  it('should include -ss for startTime', () => {
    const result = buildGifArgs(makeGifOptions({ startTime: 5 }));
    const ssIndex = result.paletteArgs.indexOf('-ss');
    expect(ssIndex).toBeGreaterThanOrEqual(0);
    expect(result.paletteArgs[ssIndex + 1]).toBe('5');
  });

  it('should include -t for duration', () => {
    const result = buildGifArgs(makeGifOptions({ duration: 10 }));
    const tIndex = result.paletteArgs.indexOf('-t');
    expect(tIndex).toBeGreaterThanOrEqual(0);
    expect(result.paletteArgs[tIndex + 1]).toBe('10');
  });

  it('should use bayer dither with bayer_scale', () => {
    const result = buildGifArgs(makeGifOptions({ dither: 'bayer' }));
    const lavfi = result.gifArgs.find((a) => a.includes('paletteuse'));
    expect(lavfi).toContain('bayer:bayer_scale=5');
  });

  it('should use floyd_steinberg dither', () => {
    const result = buildGifArgs(makeGifOptions({ dither: 'floyd_steinberg' }));
    const lavfi = result.gifArgs.find((a) => a.includes('paletteuse'));
    expect(lavfi).toContain('floyd_steinberg');
  });

  it('should use none dither', () => {
    const result = buildGifArgs(makeGifOptions({ dither: 'none' }));
    const lavfi = result.gifArgs.find((a) => a.includes('paletteuse'));
    expect(lavfi).toContain('dither=none');
  });

  it('should set loop argument in gifArgs', () => {
    const result = buildGifArgs(makeGifOptions({ loop: 3 }));
    const loopIndex = result.gifArgs.indexOf('-loop');
    expect(loopIndex).toBeGreaterThanOrEqual(0);
    expect(result.gifArgs[loopIndex + 1]).toBe('3');
  });

  it('should include output path in gifArgs', () => {
    const result = buildGifArgs(makeGifOptions());
    expect(result.gifArgs).toContain('/tmp/output.gif');
  });

  it('should use full stats_mode for high quality', () => {
    const result = buildGifArgs(makeGifOptions({ quality: 'high' }));
    const vf = result.paletteArgs.find((a) => a.includes('palettegen'));
    expect(vf).toContain('stats_mode=full');
  });

  it('should use diff stats_mode for medium quality', () => {
    const result = buildGifArgs(makeGifOptions({ quality: 'medium' }));
    const vf = result.paletteArgs.find((a) => a.includes('palettegen'));
    expect(vf).toContain('stats_mode=diff');
  });

  it('should throw on invalid options', () => {
    expect(() => buildGifArgs(makeGifOptions({ width: 5000 }))).toThrow('Invalid GIF options');
  });

  it('should include palette path in gifArgs', () => {
    const result = buildGifArgs(makeGifOptions());
    expect(result.gifArgs).toContain(result.palettePath);
  });

  it('should not include -ss when startTime is 0', () => {
    const result = buildGifArgs(makeGifOptions({ startTime: 0 }));
    expect(result.paletteArgs).not.toContain('-ss');
  });
});

// ─── buildSocialExportArgs ─────────────────────────────────────────────

describe('buildSocialExportArgs', () => {
  it('should include input path', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    expect(args).toContain('/tmp/input.mp4');
  });

  it('should include output path', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    expect(args).toContain('/tmp/output.mp4');
  });

  it('should set correct codec for h264', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    const codecIdx = args.indexOf('-c:v');
    expect(args[codecIdx + 1]).toBe('libx264');
  });

  it('should set correct codec for h265 preset', () => {
    const h265Preset: SocialMediaPreset = {
      ...SOCIAL_PRESETS.instagram_reel,
      codec: 'h265',
    };
    const args = buildSocialExportArgs(makeSocialOptions({ preset: h265Preset }));
    const codecIdx = args.indexOf('-c:v');
    expect(args[codecIdx + 1]).toBe('libx265');
  });

  it('should include video bitrate', () => {
    const args = buildSocialExportArgs(
      makeSocialOptions({ preset: SOCIAL_PRESETS.instagram_reel }),
    );
    expect(args).toContain('8M');
  });

  it('should include audio codec aac', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    const caIdx = args.indexOf('-c:a');
    expect(args[caIdx + 1]).toBe('aac');
  });

  it('should include movflags faststart', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    expect(args).toContain('+faststart');
  });

  it('should include scale and pad without crop', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    const vfIdx = args.indexOf('-vf');
    const vfValue = args[vfIdx + 1];
    expect(vfValue).toContain('scale=');
    expect(vfValue).toContain('pad=');
  });

  it('should use crop filter when crop is specified', () => {
    const args = buildSocialExportArgs(makeSocialOptions({ crop: 'center' }));
    const vfIdx = args.indexOf('-vf');
    const vfValue = args[vfIdx + 1];
    expect(vfValue).toContain('crop=');
  });

  it('should handle top crop', () => {
    const args = buildSocialExportArgs(makeSocialOptions({ crop: 'top' }));
    const vfIdx = args.indexOf('-vf');
    const vfValue = args[vfIdx + 1];
    expect(vfValue).toContain('crop=');
  });

  it('should handle bottom crop', () => {
    const args = buildSocialExportArgs(makeSocialOptions({ crop: 'bottom' }));
    const vfIdx = args.indexOf('-vf');
    const vfValue = args[vfIdx + 1];
    expect(vfValue).toContain('crop=');
    expect(vfValue).toContain('in_h-out_h');
  });

  it('should include fps in filter', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    const vfIdx = args.indexOf('-vf');
    const vfValue = args[vfIdx + 1];
    expect(vfValue).toContain('fps=30');
  });

  it('should set h264 profile and level', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    expect(args).toContain('-profile:v');
    expect(args).toContain('high');
    expect(args).toContain('-level');
    expect(args).toContain('4.1');
  });

  it('should throw on invalid options', () => {
    expect(() =>
      buildSocialExportArgs({
        inputPath: '',
        outputPath: '/tmp/out.mp4',
        preset: SOCIAL_PRESETS.tiktok,
      }),
    ).toThrow('Invalid social export options');
  });

  it('should set pix_fmt yuv420p for h264', () => {
    const args = buildSocialExportArgs(makeSocialOptions());
    expect(args).toContain('-pix_fmt');
    expect(args).toContain('yuv420p');
  });
});

// ─── estimateGifSize ───────────────────────────────────────────────────

describe('estimateGifSize', () => {
  it('should return a positive number', () => {
    const size = estimateGifSize(320, 15, 5, 'medium');
    expect(size).toBeGreaterThan(0);
  });

  it('should increase with width', () => {
    const small = estimateGifSize(240, 15, 5, 'medium');
    const large = estimateGifSize(800, 15, 5, 'medium');
    expect(large).toBeGreaterThan(small);
  });

  it('should increase with fps', () => {
    const low = estimateGifSize(320, 10, 5, 'medium');
    const high = estimateGifSize(320, 30, 5, 'medium');
    expect(high).toBeGreaterThan(low);
  });

  it('should increase with duration', () => {
    const short = estimateGifSize(320, 15, 2, 'medium');
    const long = estimateGifSize(320, 15, 20, 'medium');
    expect(long).toBeGreaterThan(short);
  });

  it('should be larger for high quality', () => {
    const low = estimateGifSize(320, 15, 5, 'low');
    const high = estimateGifSize(320, 15, 5, 'high');
    expect(high).toBeGreaterThan(low);
  });

  it('should return ~0 for very short clips', () => {
    const size = estimateGifSize(240, 10, 0.1, 'low');
    expect(size).toBeLessThan(1);
  });
});

// ─── estimateSocialSize ────────────────────────────────────────────────

describe('estimateSocialSize', () => {
  it('should return a positive number', () => {
    const size = estimateSocialSize(SOCIAL_PRESETS.tiktok, 30);
    expect(size).toBeGreaterThan(0);
  });

  it('should increase with duration', () => {
    const short = estimateSocialSize(SOCIAL_PRESETS.tiktok, 10);
    const long = estimateSocialSize(SOCIAL_PRESETS.tiktok, 60);
    expect(long).toBeGreaterThan(short);
  });

  it('should be larger for higher bitrate presets', () => {
    const low = estimateSocialSize(SOCIAL_PRESETS.whatsapp_status, 30);
    const high = estimateSocialSize(SOCIAL_PRESETS.youtube_standard, 30);
    expect(high).toBeGreaterThan(low);
  });

  it('should produce reasonable values for youtube standard 1min', () => {
    const size = estimateSocialSize(SOCIAL_PRESETS.youtube_standard, 60);
    // 10M bitrate * 60s / 8 = ~75 MB + audio
    expect(size).toBeGreaterThan(50);
    expect(size).toBeLessThan(120);
  });
});

// ─── validateGifOptions ────────────────────────────────────────────────

describe('validateGifOptions', () => {
  it('should return empty array for valid options', () => {
    const errors = validateGifOptions(makeGifOptions());
    expect(errors).toEqual([]);
  });

  it('should reject empty inputPath', () => {
    const errors = validateGifOptions(makeGifOptions({ inputPath: '' }));
    expect(errors).toContain('inputPath is required');
  });

  it('should reject empty outputPath', () => {
    const errors = validateGifOptions(makeGifOptions({ outputPath: '' }));
    expect(errors).toContain('outputPath is required');
  });

  it('should reject width > GIF_MAX_WIDTH', () => {
    const errors = validateGifOptions(makeGifOptions({ width: 1000 }));
    expect(errors.some((e) => e.includes('width'))).toBe(true);
  });

  it('should reject width < GIF_MIN_WIDTH', () => {
    const errors = validateGifOptions(makeGifOptions({ width: 50 }));
    expect(errors.some((e) => e.includes('width'))).toBe(true);
  });

  it('should reject fps < GIF_MIN_FPS', () => {
    const errors = validateGifOptions(makeGifOptions({ fps: 5 }));
    expect(errors.some((e) => e.includes('fps'))).toBe(true);
  });

  it('should reject fps > GIF_MAX_FPS', () => {
    const errors = validateGifOptions(makeGifOptions({ fps: 60 }));
    expect(errors.some((e) => e.includes('fps'))).toBe(true);
  });

  it('should reject duration > GIF_MAX_DURATION', () => {
    const errors = validateGifOptions(makeGifOptions({ duration: 60 }));
    expect(errors.some((e) => e.includes('duration'))).toBe(true);
  });

  it('should reject negative loop', () => {
    const errors = validateGifOptions(makeGifOptions({ loop: -1 }));
    expect(errors.some((e) => e.includes('loop'))).toBe(true);
  });

  it('should reject negative startTime', () => {
    const errors = validateGifOptions(makeGifOptions({ startTime: -5 }));
    expect(errors.some((e) => e.includes('startTime'))).toBe(true);
  });

  it('should accept valid boundary values', () => {
    const errors = validateGifOptions(
      makeGifOptions({ width: GIF_MAX_WIDTH, fps: GIF_MAX_FPS, duration: GIF_MAX_DURATION }),
    );
    expect(errors).toEqual([]);
  });
});

// ─── validateSocialOptions ─────────────────────────────────────────────

describe('validateSocialOptions', () => {
  it('should return empty array for valid options', () => {
    const errors = validateSocialOptions(makeSocialOptions());
    expect(errors).toEqual([]);
  });

  it('should reject empty inputPath', () => {
    const errors = validateSocialOptions(makeSocialOptions({ inputPath: '' }));
    expect(errors).toContain('inputPath is required');
  });

  it('should reject empty outputPath', () => {
    const errors = validateSocialOptions(makeSocialOptions({ outputPath: '' }));
    expect(errors).toContain('outputPath is required');
  });

  it('should accept valid crop values', () => {
    for (const crop of ['center', 'top', 'bottom'] as const) {
      const errors = validateSocialOptions(makeSocialOptions({ crop }));
      expect(errors).toEqual([]);
    }
  });
});

// ─── getPreset ─────────────────────────────────────────────────────────

describe('getPreset', () => {
  const platforms: SocialPlatform[] = [
    'instagram_reel',
    'instagram_post',
    'instagram_story',
    'tiktok',
    'youtube_shorts',
    'youtube_standard',
    'twitter',
    'linkedin',
    'facebook',
    'whatsapp_status',
  ];

  it.each(platforms)('should return preset for %s', (platform) => {
    const preset = getPreset(platform);
    expect(preset).toBeDefined();
    expect(preset.platform).toBe(platform);
    expect(preset.width).toBeGreaterThan(0);
    expect(preset.height).toBeGreaterThan(0);
  });

  it('should throw for unknown platform', () => {
    expect(() => getPreset('unknown_platform' as SocialPlatform)).toThrow('Unknown platform');
  });
});

// ─── listPresets ───────────────────────────────────────────────────────

describe('listPresets', () => {
  it('should return 10 presets', () => {
    const presets = listPresets();
    expect(presets).toHaveLength(10);
  });

  it('should return all with required fields', () => {
    const presets = listPresets();
    for (const p of presets) {
      expect(p.name).toBeTruthy();
      expect(p.platform).toBeTruthy();
      expect(p.width).toBeGreaterThan(0);
      expect(p.height).toBeGreaterThan(0);
      expect(p.fps).toBeGreaterThan(0);
      expect(p.videoBitrate).toBeTruthy();
      expect(p.audioBitrate).toBeTruthy();
      expect(p.label).toBeTruthy();
    }
  });
});

// ─── getPresetsForAspectRatio ──────────────────────────────────────────

describe('getPresetsForAspectRatio', () => {
  it('should return multiple 9:16 presets', () => {
    const presets = getPresetsForAspectRatio('9:16');
    expect(presets.length).toBeGreaterThanOrEqual(4); // reel, story, tiktok, shorts, whatsapp
    for (const p of presets) {
      expect(p.aspectRatio).toBe('9:16');
    }
  });

  it('should return instagram_post for 1:1', () => {
    const presets = getPresetsForAspectRatio('1:1');
    expect(presets.length).toBeGreaterThanOrEqual(1);
    expect(presets.some((p) => p.platform === 'instagram_post')).toBe(true);
  });

  it('should return 16:9 presets', () => {
    const presets = getPresetsForAspectRatio('16:9');
    expect(presets.length).toBeGreaterThanOrEqual(3); // youtube, twitter, linkedin, facebook
    for (const p of presets) {
      expect(p.aspectRatio).toBe('16:9');
    }
  });
});

// ─── SOCIAL_PRESETS ────────────────────────────────────────────────────

describe('SOCIAL_PRESETS', () => {
  it('should have 10 platforms', () => {
    expect(Object.keys(SOCIAL_PRESETS)).toHaveLength(10);
  });

  it('should have all required fields on every preset', () => {
    for (const [key, preset] of Object.entries(SOCIAL_PRESETS)) {
      expect(preset.name).toBeTruthy();
      expect(preset.platform).toBe(key);
      expect(preset.width).toBeGreaterThan(0);
      expect(preset.height).toBeGreaterThan(0);
      expect(preset.maxDuration).toBeGreaterThan(0);
      expect(preset.maxFileSize).toBeGreaterThan(0);
      expect(preset.fps).toBeGreaterThan(0);
      expect(preset.videoBitrate).toMatch(/^\d+M$/);
      expect(preset.audioBitrate).toMatch(/^\d+k$/);
      expect(['h264', 'h265']).toContain(preset.codec);
      expect(['mp4', 'webm']).toContain(preset.format);
      expect(preset.aspectRatio).toMatch(/^\d+:\d+$/);
      expect(preset.label).toBeTruthy();
    }
  });
});

// ─── estimateExport ────────────────────────────────────────────────────

describe('estimateExport', () => {
  it('should return estimate for GIF', () => {
    const result = estimateExport({
      type: 'gif',
      gifOptions: makeGifOptions({ duration: 5 }),
    });
    expect(result.estimatedSizeMB).toBeGreaterThan(0);
    expect(result.estimatedDurationSeconds).toBe(5);
    expect(Array.isArray(result.warnings)).toBe(true);
  });

  it('should warn for large GIF', () => {
    const result = estimateExport({
      type: 'gif',
      gifOptions: makeGifOptions({ width: 800, fps: 30, duration: 30, quality: 'high' }),
    });
    expect(result.warnings.length).toBeGreaterThan(0);
  });

  it('should return estimate for social', () => {
    const result = estimateExport({
      type: 'social',
      socialOptions: makeSocialOptions(),
      durationSeconds: 30,
    });
    expect(result.estimatedSizeMB).toBeGreaterThan(0);
    expect(result.estimatedDurationSeconds).toBe(30);
  });

  it('should warn when duration exceeds preset max', () => {
    const result = estimateExport({
      type: 'social',
      socialOptions: makeSocialOptions({ preset: SOCIAL_PRESETS.whatsapp_status }),
      durationSeconds: 60, // max is 30
    });
    expect(result.warnings.some((w) => w.includes('Duration'))).toBe(true);
  });

  it('should warn when size exceeds preset max', () => {
    const result = estimateExport({
      type: 'social',
      socialOptions: makeSocialOptions({ preset: SOCIAL_PRESETS.whatsapp_status }),
      durationSeconds: 300, // will blow past 16MB max
    });
    expect(result.warnings.some((w) => w.includes('size'))).toBe(true);
  });

  it('should use default 10s for GIF without duration', () => {
    const result = estimateExport({
      type: 'gif',
      gifOptions: makeGifOptions({ duration: undefined }),
    });
    expect(result.estimatedDurationSeconds).toBe(10);
  });
});
